VALUES
  ('fire-eq-tech-moex-03020', 'fire-eq-tech', 'fire-eq-tech-moex-098-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」第 163 條規定，緩降機於設置周圍無操作障礙，並保有之必要操 作面積規定為何？', '["寬一百五十公分以上，長一百五十公分以上（含器具所佔面積）", "依避難器具大小及形狀留置之", "零點五平方公尺以上（不含避難器具所佔面積），但邊長應為六十公分以上", "高六十公分以上，寬六十公分以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "50066680056f", "answer_pdf_sha1": "b923dcb45e86", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03021', 'fire-eq-tech', 'fire-eq-tech-moex-098-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」第170條規定，何者並非救助袋設置規定？', '["救助袋之長度應無避難上之障礙，且保持一定之安全下滑速度", "裝置在使用場所之柱、地板、樑或其他構造上堅固或加強部分", "救助袋支固器具以螺栓、熔接或其他堅固方法裝置", "構造、材質、強度及標示符合CNS、一三二三一之規定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "50066680056f", "answer_pdf_sha1": "b923dcb45e86", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03022', 'fire-eq-tech', 'fire-eq-tech-moex-098-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '進入安全梯之出入口，應符合下列何者之規定？', '["裝設具有一小時以上防火時效，且具有半小時以上阻熱性之防火門，並不得設置門檻；其寬度不得小 於九十公分", "具有一小時以上防火時效，天花板及牆面之裝修材料採用耐燃一級材料", "有緊急電源之照明設備", "開設採光用之向外窗戶或開口者，應與同幢建築物之其他窗戶或開口相距九十公分以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "50066680056f", "answer_pdf_sha1": "b923dcb45e86", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03023', 'fire-eq-tech', 'fire-eq-tech-moex-098-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '自室內經由陽臺或排煙室始得進入之安全梯稱為？', '["直通樓梯", "室內安全梯", "戶外安全梯", "特別安全梯"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "50066680056f", "answer_pdf_sha1": "b923dcb45e86", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03024', 'fire-eq-tech', 'fire-eq-tech-moex-098-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某建築物樓層高度超過十層樓，其以上部分之樓層最大樓地板面積為五○○○平方公尺，緊急用昇降機 應設置幾座？', '["五座", "二座", "三座", "四座"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "50066680056f", "answer_pdf_sha1": "b923dcb45e86", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03025', 'fire-eq-tech', 'fire-eq-tech-moex-098-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '電影院直通樓梯於避難層開向屋外之其他出入口，其寬度及高度之規定為何？', '["寬度不得小於一‧三公尺，高度不得小於一‧八公尺", "寬度不得小於一‧二公尺，高度不得小於一‧八公尺", "寬度不得小於一‧二公尺，高度不得小於一‧九公尺", "寬度不得小於一‧三公尺，高度不得小於一‧九公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "50066680056f", "answer_pdf_sha1": "b923dcb45e86", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03026', 'fire-eq-tech', 'fire-eq-tech-moex-098-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '多年前台北縣蘆洲市大囍市社區火災，多人使用緩降機但仍不幸罹難，其主要原因為何？', '["緩降機過於老舊", "未將安全帶上之束環束緊", "自家之緩降機已拆除，僅抓住較高樓層緩降機之繩索", "下落時撞擊異物"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "50066680056f", "answer_pdf_sha1": "b923dcb45e86", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
